sql:
SELECT constant_id, identifier, name, value
FROM constants
WHERE constant_id = 1;

SELECT constant_id, description
FROM constants
WHERE LENGTH(description) = (
    SELECT MAX(LENGTH(description))
    FROM constants
);

SELECT * 
FROM constants 
WHERE is_active = 1 AND value > 100;

SELECT constant_id, identifier, name
FROM constants
ORDER BY constant_id ASC;

external_knowledge:
- "beacon" refers to a constant identifier;
- "brightest" is metaphorical for the most recently updated or the highest version;
- "stars" metaphorically represent constants;
- "stargazer" refers to a user who modifies the constants;
- "most prolific" is a metaphor indicating the user with the highest activity level, as determined by the number of access logs;
- "marking the skyline with the latest shine" metaphorically describes the selection of the constant with the highest version number.

sql:
SELECT user_id, constant_id, access_date, access_type, ip_address, user_agent 
FROM access_logs 
WHERE constant_id = (SELECT constant_id FROM constants WHERE uncertainty = (SELECT MAX(uncertainty) FROM constants));

SELECT type_name
FROM constant_types
WHERE is_standard = 1;

SELECT * 
FROM constant_links 
WHERE DATE(last_checked_at) < DATE('now', '-30 days');

SELECT identifier, type_id, description
FROM constants
ORDER BY identifier ASC;

SELECT u.user_name
FROM users u
JOIN constant_versions cv ON u.user_id = cv.changed_by
WHERE cv.created_at = (
    SELECT MAX(created_at) FROM constant_versions
);

SELECT constant_id, name, type_id 
FROM constants 
WHERE constant_id = 1;
